mapper.select:
SELECT id, tenant_id, batch_code, name, denomination, total_count,
       status, expire_at, created_by_id, created_at, updated_at
FROM recharge_card_batch WHERE id = #{id}

SELECT id, tenant_id, batch_code, name, denomination, total_count,
       status, expire_at, created_by_id, created_at, updated_at
FROM recharge_card_batch
WHERE id = #{id}
AND tenant_id = #{tenantId}

SELECT b.id AS id, b.tenant_id AS tenantId, t.tenant_code AS tenantCode, t.name AS tenantName, b.batch_code AS batchCode, b.name AS name, b.denomination AS denomination, b.total_count AS totalCount, (SELECT COUNT(*) FROM recharge_card c WHERE c.batch_id = b.id AND c.status = 'ENABLED' AND (c.expire_at IS NULL OR c.expire_at > NOW())) AS availableCount, (SELECT COUNT(*) FROM recharge_card c WHERE c.batch_id = b.id AND c.status = 'REDEEMED') AS usedCount, (SELECT COUNT(*) FROM recharge_card c WHERE c.batch_id = b.id AND c.status = 'DISABLED') AS disabledCount, (SELECT COUNT(*) FROM recharge_card c WHERE c.batch_id = b.id AND ((c.status = 'EXPIRED') OR (c.status = 'ENABLED' AND c.expire_at IS NOT NULL AND c.expire_at <= NOW()))) AS expiredCount, b.status AS status, b.expire_at AS expireAt, b.created_by_id AS createdById, u.display_name AS createdByName, b.created_at AS createdAt, b.updated_at AS updatedAt FROM recharge_card_batch b INNER JOIN tenant t ON t.id = b.tenant_id LEFT JOIN user_account u ON u.id = b.created_by_id WHERE 1 = 1 AND b.tenant_id = #{tenantId}
AND (b.batch_code ILIKE CONCAT('%', #{keyword}, '%') OR b.name ILIKE CONCAT('%', #{keyword}, '%'))
AND b.status = #{status} AND b.denomination = #{denomination} ORDER BY b.created_at DESC, b.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM recharge_card_batch b
WHERE 1 = 1
AND b.tenant_id = #{tenantId}

    AND (b.batch_code ILIKE CONCAT('%', #{keyword}, '%')
      OR b.name ILIKE CONCAT('%', #{keyword}, '%'))

AND b.status = #{status}
AND b.denomination = #{denomination}

SELECT c.id AS id, c.tenant_id AS tenantId, c.batch_id AS batchId, b.batch_code AS batchCode, c.card_prefix AS cardPrefix, c.denomination AS denomination, c.status AS status, c.expire_at AS expireAt, c.redeemed_user_id AS redeemedUserId, u.username AS redeemedUsername, u.display_name AS redeemedUserDisplayName, c.redeemed_at AS redeemedAt, c.created_at AS createdAt FROM recharge_card c INNER JOIN recharge_card_batch b ON b.id = c.batch_id LEFT JOIN user_account u ON u.id = c.redeemed_user_id WHERE 1 = 1 AND c.batch_id = #{batchId} AND c.tenant_id = #{tenantId}
AND c.card_prefix ILIKE CONCAT('%', #{prefixKeyword}, '%')
AND c.status = #{status} ORDER BY c.created_at DESC, c.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM recharge_card c
WHERE 1 = 1
AND c.batch_id = #{batchId}
AND c.tenant_id = #{tenantId}

    AND c.card_prefix ILIKE CONCAT('%', #{prefixKeyword}, '%')

AND c.status = #{status}
